var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그만해요! 에델을 고슴도치로 만들 셈인가요?!","JPN":"そ、それくらいにしてください！　エデルをハリネズミにするつもりですの！？","ENG":"S-stop! You're going to kill her!","TWN":"住，住手！妳想把艾瑟兒釘成刺蝟嗎？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"걱정 마. 비주얼이 좀 끔찍하긴 하지만 에델은 이 정도론 안 죽어.","JPN":"心配いらないよ。見た目はちょっとアレだけど、エデルはこのくらいじゃ死なないから。","ENG":"Don't worry. As awful as it may look, Edel won't die from this.","TWN":"別擔心。雖然視覺上有點可怕，但艾瑟兒不會因為這種程度死掉。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델은 대식가라서 말이야. 가끔 허기로 맛이 가면 말려 줄 사람이 필요해.","JPN":"エデルは大喰らいだからさ。時々お腹が空きすぎて正気を失ったら、止めてあげる人が必要なの。","ENG":"Edel is a very enthusiastic binge eater. When she gets too hungry and loses it, someone has to stop her.","TWN":"艾瑟兒是個大胃王啊。她有時會因為饑餓發狂，所以需要有人阻止她。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그럴 때마다 정신이 돌아올 때까지 이 봉인주로 에델을 못박아 두는 게 내 일이거든.","JPN":"そのたびに正気に戻るまでこの封印柱でエデルを動けなくするのが、アタシの仕事なんだ。","ENG":"It's my job to nail her down with these sealing stakes until she comes to her senses.","TWN":"每次在艾瑟兒清醒過來之前，用封印槍把她釘起來就是我的工作。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이런 걸로 못박히면 사람은 죽어요!","JPN":"こんなやり方では人は死んでしまいますわ！","ENG":"No one's going to survive that much nailing-down!","TWN":"用這種東西會釘死人的！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델이 아직도 사람이라고 생각해?","JPN":"まだエデルが人だと思ってるの？","ENG":"You still think Edel is like one of us?","TWN":"妳現在還覺得艾瑟兒是人嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만...... 아니, 그 촉수들은 분명......","JPN":"でも……いや、あの触手は確かに……","ENG":"But... No, those tentacles were actually...","TWN":"但是… 不，那些觸手肯定是……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델은...... 에델은 뭐죠?","JPN":"エデルは……エデルは何者なのです？","ENG":"What... What is Edel?","TWN":"艾瑟兒……艾瑟兒究竟是什麼？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"글쎄? 공포소설에 자주 나오는 촉수 달린 괴물?","JPN":"さあね。ホラー小説によく出てくる触手の怪物？","ENG":"I don't know. A tentacled monster, like the ones in horror fictions?","TWN":"誰知道？恐怖小說裡經常出現的觸手怪物？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지금 그런 오컬트 같은 황당한 소리나 할 상황이에요?!","JPN":"そんなオカルトのようなあり得ないことを言ってる場合ですか！？","ENG":"Will you stop trying to be funny with the stupid occult references?","TWN":"現在是說這種不合理超自然現象的時候嗎？！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"......레지나야말로 무슨 소리야?","JPN":"……レジーナこそ、何言ってんの？","ENG":"What are you talking about?","TWN":"……蕾佳娜妳才是在說什麼呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"나 같은 용병들에겐 지금이 바로 오컬트의 시대라고.","JPN":"アタシみたいな傭兵にとって、この時代はオカルトそのものなんだけど。","ENG":"It's been some time now since this world started to look like a giant stage for occult movies, especially to mercenaries like me.","TWN":"對我這種傭兵而言，現在就是超自然的時代啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네......?","JPN":"えっ……？","ENG":"Huh?","TWN":"什麼……?"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"다른 세상에서 괴물들이 넘어오고 사람들은 손에서 뿜어내는 불로 그 괴물들을 잡아. 그리고 괴물의 시체에서 마법의 돌을 끄집어내지.","JPN":"他の世界から怪物がやって来て、\\n人は手から放たれる炎でその怪物を倒すの。\\nそして怪物の死体から魔法の石を抉り出すんだよ。","ENG":"Monsters are invading from the other world, and there are people hunting them down, shooting fire from their palms. And they pull magic stones out of the dead monsters afterward.","TWN":"怪物從另一個世界過來，而人們從手中噴出火焰殺死它們，並且從怪物的屍體中取出魔法石頭。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"대체 어디까지가 현실이고 어디까지가 비현실이지?","JPN":"いったいどこまでが現実で、どこからが非現実なの？","ENG":"The line between fiction and reality has become blurry, Regina.","TWN":"究竟到什麼程度才是現實，到什麼程度才是非現實？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"這個……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};